     8→TeamAccessibleContents _createBaseTeamAccessibleContents() {
     9→  return {
    10→    for (final domain in RoleDomain.values)
    11→      if (domain != RoleDomain.unknown)
    12→        domain: _createDomainAccessibleContents(null, false),
    13→  };
    14→}
    15→
    16→UserAccessibleContents _createTeamAccessibleContents(
    17→    String teamId, AppRole role) {
    18→  switch (role) {
    19→    case AppRole.teamAdmin:
    20→      final contents = _createBaseTeamAccessibleContents();
    21→      contents[RoleDomain.basic] =
    22→          _createDomainAccessibleContents(RoleLevel.admin, true);
    23→      contents[RoleDomain.management] =
    24→          _createDomainAccessibleContents(RoleLevel.admin, true);
    25→      return {teamId: contents};
    26→    case AppRole.teamManager:
    27→      final contents = _createBaseTeamAccessibleContents();
    28→      contents[RoleDomain.basic] =
    29→          _createDomainAccessibleContents(RoleLevel.write, true);
    30→      return {teamId: contents};
    31→    case AppRole.teamMember:
    32→      final contents = _createBaseTeamAccessibleContents();
    33→      contents[RoleDomain.basic] =
    34→          _createDomainAccessibleContents(RoleLevel.write, false);
    35→      return {teamId: contents};
    36→    case AppRole.personalUser:
    37→      final contents = _createBaseTeamAccessibleContents();
    38→      contents[RoleDomain.basic] =
    39→          _createDomainAccessibleContents(RoleLevel.write, true);
    40→      return {teamId: contents};
    41→    case AppRole.superReader:
    42→      final teamContents = _createBaseTeamAccessibleContents();
    43→      teamContents[RoleDomain.basic] =
    44→          _createDomainAccessibleContents(RoleLevel.read, true);
    45→      teamContents[RoleDomain.management] =
    46→          _createDomainAccessibleContents(RoleLevel.read, true);
    47→      teamContents[RoleDomain.admin] =
    48→          _createDomainAccessibleContents(RoleLevel.read, true);
    49→      final allTeamsContents = _createBaseTeamAccessibleContents();
    50→      allTeamsContents[RoleDomain.basic] =
    51→          _createDomainAccessibleContents(RoleLevel.read, true);
    52→      allTeamsContents[RoleDomain.management] =
    53→          _createDomainAccessibleContents(RoleLevel.read, true);
    54→      allTeamsContents[RoleDomain.admin] =
    55→          _createDomainAccessibleContents(RoleLevel.read, true);
    56→      return {teamId: teamContents, allTeams: allTeamsContents};
    57→    case AppRole.superAdmin:
    58→      final teamContents = _createBaseTeamAccessibleContents();
    59→      teamContents[RoleDomain.basic] =
    60→          _createDomainAccessibleContents(RoleLevel.read, true);
    61→      teamContents[RoleDomain.management] =
    62→          _createDomainAccessibleContents(RoleLevel.read, true);
    63→      teamContents[RoleDomain.admin] =
    64→          _createDomainAccessibleContents(RoleLevel.write, true);
    65→      final allTeamsContents = _createBaseTeamAccessibleContents();
    66→      allTeamsContents[RoleDomain.basic] =
    67→          _createDomainAccessibleContents(RoleLevel.read, true);
    68→      allTeamsContents[RoleDomain.management] =
    69→          _createDomainAccessibleContents(RoleLevel.read, true);
    70→      allTeamsContents[RoleDomain.admin] =
    71→          _createDomainAccessibleContents(RoleLevel.write, true);
    72→      return {teamId: teamContents, allTeams: allTeamsContents};
    73→    default:
    74→      throw Exception('unexpected AppRole: $role');
    75→  }
    76→}
    77→
    78→DomainAccessibleContents _createDomainAccessibleContents(
    79→    RoleLevel? level, bool isTeamCrossing) {
    80→  final allow =
    81→      ShortRoleInfo(isAccessible: true, isTeamCrossing: isTeamCrossing);
    82→  const deny = ShortRoleInfo(isAccessible: false, isTeamCrossing: false);
    83→
    84→  switch (level) {
    85→    case RoleLevel.admin:
