enum ResourceStatusType {
  none,
  onLocalStorage,
  onAnalysisServerQueue,
  inAnalysis,
  analysisFailed,
  analysisSucceeded,
  insufficientBalls;

  bool get isOnLocalStorage => this == ResourceStatusType.onLocalStorage;
}

@unfreezed
abstract class ResourceData with _$ResourceData {
  // Countermeasure for the error of seeder generator when referring to dart:ui with a model
  static bool Function(ResourceData) isOnLocalStorage = (_) => false;

  ResourceData._();

  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  factory ResourceData({
    // remote data
    final String? appVersion,
    final String? id,
    final double? focalLength,
    final double? longsideAngleOfView,
    final double? fps,
    final String? uploadFilename,
    final String? originalVideoFilename,
    final int? movieWidth,
    final int? movieHeight,
    final double? movieTime,
    final int? status,
    final DateTime? createdAt, // assumes UTC
    final DateTime? updatedAt, // assumes UTC
    final DateTime? recordedAt, // assumes UTC
    final bool? deleteFlag,
    final String? userId,
    final String? sessionId,
    final double? accX,
    final double? accY,
    final double? accZ,
    final double? focus,
    final double? iso,
    final String? lens,
    final double? shutterSpeed,
    final double? zoom,
    final String? device,
    final bool? isAutoFocus,
    @JsonBigIntConverter() final int? analyzeType,
    final UnitType? unit,
    final String? cameraMode,
    final String? algorithmVersion,
    final String? presignedOriginalVideoUrl,
    final Session? session,
    final String? teamPlanId,
    final TeamPlan? teamPlan,
    final List<BallInfo>? ballInfoList,

    // data filled by repository
    @JsonKey(includeToJson: false) final String? teamId,

    // local data
    @JsonKey(includeToJson: false) final String? pathVideoOnLocal,
  }) = _ResourceData;

