import '../../_common/create_accessible_contents.dart';

void main() {
  group('Testing UserInfo and UserAccessibleContents', () {
    const id = '22222222-0000-0000-0000-000000000000';
    const teamId = '11111111-0001-0000-0000-000000000000';
    final createdAt = DateTime(2024, 1, 1, 1, 1);
    final updatedAt = DateTime(2024, 1, 1, 2, 1);

    final userInfo = UserInfo(
      id: id,
      email: 'user2_team1_admin@test.com',
      deletedAt: null,
      createdAt: createdAt,
      updatedAt: updatedAt,
      profile: Profile(
        id: '00000000-0000-4000-8000-000000000000',
        username: 'test name',
        imageUrl: 'https://example.test/image.jpg',
        presignedImageUrl: 'https://example.test/image.jpg?presigned',
        createdAt: createdAt,
        updatedAt: updatedAt,
      ),
      accessibleContents: createAccessibleContents({
        teamId: [AppRole.teamAdmin]
