              type: 1,
              maxBalls: 100,
              createdAt: createdAt,
              updatedAt: updatedAt,
            ),
          ),
        ),
      ],
    );

    test('toJson1', () {
      final userInfoJson = userInfo.toJson();

      expect(userInfoJson.length, 9);

