                'isTeamCrossing': teamBasicRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamBasicWrite.isAccessible,
                'isTeamCrossing': teamBasicWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamBasicAdmin.isAccessible,
                'isTeamCrossing': teamBasicAdmin.isTeamCrossing,
              },
            },
            'management': {
              'read': {
                'isAccessible': teamManagementRead.isAccessible,
                'isTeamCrossing': teamManagementRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamManagementWrite.isAccessible,
                'isTeamCrossing': teamManagementWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamManagementAdmin.isAccessible,
                'isTeamCrossing': teamManagementAdmin.isTeamCrossing,
              },
            },
          }
        },
        'givenUserRoles': {
          teamId: [userRoleJson],
        },
        'teams': [teamJson],
      };

      final deserialized = UserInfo.fromJson(userInfoJson);

      expect(deserialized.id, userInfo.id);
      expect(deserialized.email, userInfo.email);
      expect(deserialized.deletedAt, userInfo.deletedAt);
      expect(deserialized.createdAt, userInfo.createdAt);
      expect(deserialized.updatedAt, userInfo.updatedAt);
      expect(deserialized.profile, userInfo.profile);
      // idはString化されているはずなので、他のフィールドで比較
      expect(deserialized.givenUserRoles[teamId]![0].userId, userRole.userId);
      expect(deserialized.givenUserRoles[teamId]![0].roleGroupId,
          userRole.roleGroupId);
      expect(deserialized.accessibleContents, userInfo.accessibleContents);
      expect(deserialized.teams[0].name, userInfo.teams[0].name);
      expect(deserialized.teams[0].teamPlan?.plan?.id,
          userInfo.teams[0].teamPlan?.plan?.id);
      // toJsonでidがString化されることも確認
      final serializedJson = deserialized.toJson();
      expect(serializedJson['givenUserRoles'][teamId][0]['id'].toString(),
          '12345');
      expect(serializedJson['teams'][0]['teamPlan']['id'].toString(), '67890');
    });
  });
}

